import{_ as i,c as n,a as s,o as a}from"./app-CEcM0piI.js";const l={};function r(t,e){return a(),n("div",null,e[0]||(e[0]=[s(`<ol><li>回调函数 容易出现回调函数地狱，多层回调函数嵌套，每种任务的处理结果存在两种可能（成功或失败）那么需要在每种任务执行完成后分别处理这两种可能</li><li>Promise 通过Promise的then处理链式调用可避免回调函数地狱的问题。但可读性依旧不好维护</li><li>Generator 最大的特点就是可以交出函数的执行权。Generator函数可以看出是异步任务的容器，在需要暂停的地方，都用yield语法来标注。 是js中的协程</li><li>async/await async 是 Generator 函数的语法糖，async/await的优点是代码清晰。可以处理回调地狱的问题 可以以同步代码的方式执行异步逻辑，使代码更加可读</li></ol><h3 id="promise" tabindex="-1"><a class="header-anchor" href="#promise"><span>Promise</span></a></h3><p>Promise有三种状态：</p><ol><li>待定（pending）：初始状态，既没有被完成，也没有被拒绝</li><li>已完成（fulfilled）：操作成功完成</li><li>已拒绝（rejected）：操作失败</li></ol><p><strong>Promise利用了三大技术手段来解决回调地狱：</strong></p><ol><li>回调函数延迟绑定 使用<code>Promise.then()</code>就是回调函数延迟绑定</li><li>返回值穿透 在Promise中返回值也是Promise，在前面的<code>Promise.then</code>中返回的Promise可以被后续的then函数处理这就是返回值穿透 使用这种方法与回调函数延迟绑定可以将回调函数嵌套的形式转换成链式调用的形式，没有那么多嵌套层级可读性有了一定的提高</li><li>错误冒泡 由于返回值穿透，当前面的Promise执行出错后返回的Promise也是错误的，错误结果可以在Promise中传递，这就是错误冒泡 多层Promise的错误只需要在结尾使用一个catch处理即可</li></ol><h3 id="generator" tabindex="-1"><a class="header-anchor" href="#generator"><span>Generator</span></a></h3><p>本质上，整个Generator函数就是一个封装的异步任务，或者说是异步任务的容器。 yield命令是异步不同阶段的分界线，有时也会把yield当成是return，yield跟return有本质的不同。</p><p>协程</p><p>声明方法</p><p>声明generator函数是在声明普通函数的function关键字后加上一个<code>*</code></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>function* func(){</span></span>
<span class="line"><span>	yield 1</span></span>
<span class="line"><span>	yield 2</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>for(let a=0;a&lt;3;++a){</span></span>
<span class="line"><span>	console.log(func.next())</span></span>
<span class="line"><span>}  //1,2,undefined</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>协程函数需要调用next函数来开始执行，执行到yield就会暂时返回，再次调用next时将从上次yield返回的地方继续执行，如果整个协程函数已经执行完毕再次调用next将返回undefined</p><ul><li>function*：声明协程函数</li><li>yield：暂时返回关键字。返回一个迭代器对象，该对象有value（yield的返回值）和done（是否完成）两个属性</li><li>next()：开始执行协程函数，直到遇到yield时暂停</li><li>yield*：遍历执行协程函数的语法糖，如果在协程函数中需要执行另一个协程函数，使用遍历的方法会导致嵌套过深，使用yield*语法糖能一次性将一个协程函数全部执行完毕<code>yield* func()</code> 使用调用普通函数的方法调用协程函数协程函数是不会执行的，会阻塞住，只有使用其内部的next函数调用才会执行</li></ul><h1 id="script标签中的async和defer" tabindex="-1"><a class="header-anchor" href="#script标签中的async和defer"><span>script标签中的async和defer</span></a></h1><ul><li>script：会阻碍HTML解析，只有下载好并执行完脚本才会继续解析HTML。</li><li>async script：解析HTML过程中进行脚本的异步下载，下载成功立马执行，有可能会阻断HTML的解析。</li><li>defer script：完全不会阻碍HTML的解析，解析完成之后再按照顺序执行脚本。 ![[Pasted image 20250615181754.png]]</li></ul><p>使用async的脚本虽然没有阻塞的情况，但无法确定什么时候执行，如果其中有修改dom的脚本而此时修改的dom又没有解析就会出错 defer会在html解析的同时异步下载脚本，只有html解析完毕才开始执行脚本</p>`,17)]))}const p=i(l,[["render",r]]),c=JSON.parse('{"path":"/front/principle/7/","title":"7 异步","lang":"zh-CN","frontmatter":{"title":"7 异步","createTime":"2025/06/18 21:14:20","permalink":"/front/principle/7/"},"readingTime":{"minutes":3.41,"words":1023},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/原理/7 异步.md","headers":[]}');export{p as comp,c as data};
